package checkdigit_test

import (
	"testing"

	"github.com/osamingo/checkdigit"
)

func TestDamm_GenerateEquivalence(t *testing.T) {
	testCases := []struct {
		name    string
		seed    string
		want    int
		wantErr bool
	}{
		{
			name:    "Empty string",
			seed:    "",
			want:    0,
			wantErr: true,
		},
		{
			name:    "Non-numeric character",
			seed:    "123a456",
			want:    0,
			wantErr: true,
		},
		{
			name:    "Valid numeric string - single digit",
			seed:    "5",
			want:    9, // Matrix lookup for interim=0, digit=5 gives 9
		},
		{
			name:    "Valid numeric string - multiple digits",
			seed:    "1234",
			want:    0, // Should be calculable through matrix lookups
		},
		{
			name:    "Valid numeric string - longer",
			seed:    "9876543210",
			want:    3, // Should be calculable through matrix lookups
		},
	}

	damm := checkdigit.NewDamm()
	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			got, err := damm.Generate(tc.seed)

			// Check error condition
			if (err != nil) != tc.wantErr {
				t.Errorf("Generate() error = %v, wantErr %v", err, tc.wantErr)
				return
			}

			// If no error expected, check result
			if !tc.wantErr && got != tc.want {
				t.Errorf("Generate() = %v, want %v", got, tc.want)
			}
		})
	}
}

