        let gtin_instance = gtin {
            digit: 10,
            pos_corr: false,
        };

        // Valid seed test
        let result = gtin_instance.generate("123456789");
        assert!(result.is_ok());
        assert_eq!(result.unwrap(), 5);

        // Empty seed test
        let result = gtin_instance.generate("");
        assert!(result.is_err());
    }

