fn verify(&self, code: &str) -> bool {
    // Check if code is at least 2 characters long
    if code.len() < 2 {
        return false;
    }

    // Generate the check digit for all but the last character
    let result = self.generate(&code[..code.len() - 1]);

    // Get the last character of code
    let last_char = code.chars().last().unwrap();

    // Check if last character is a digit
    if !last_char.is_ascii_digit() {
        return false;
    }

    // Convert last character to a digit (equivalent to code[len(code)-1]-'0' in Go)
    let last_digit = (last_char as u8 - b'0') as i32;

    // Return true if no error and the generated digit equals the last digit
    match result {
        Ok(digit) => digit == last_digit,
        Err(_) => false,
    }
}

