package checkdigit

import (
	"bytes"
	"os"
	"testing"
)

// TestVerifyOutputFormat tests the verify function to ensure it prints the result in the correct format.
func TestVerifyOutputFormat(t *testing.T) {
	testCases := []struct {
		name     string
		provider Provider
		target   string
		expected string // Expected stderr output
		result   bool   // Expected return value
	}{
		{
			name:     "verify with true result",
			provider: mockProvider{verifyResult: true},
			target:   "test123",
			expected: "true\n",
			result:   true,
		},
		{
			name:     "verify with false result",
			provider: mockProvider{verifyResult: false},
			target:   "test456",
			expected: "false\n",
			result:   false,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			// Redirect stderr to capture output
			oldStderr := os.Stderr
			r, w, _ := os.Pipe()
			os.Stderr = w

			// Call the verify function
			result := verify(tc.provider, tc.target)

			// Close the writer to get the output
			w.Close()
			os.Stderr = oldStderr

			var buf bytes.Buffer
			buf.ReadFrom(r)
			output := buf.String()

			// Check the stderr output
			if output != tc.expected {
				t.Errorf("Expected stderr output: %q, got: %q", tc.expected, output)
			}

			// Check the return value
			if result != tc.result {
				t.Errorf("Expected return value: %v, got: %v", tc.result, result)
			}
		})
	}
}

// mockProvider is a simple mock of the Provider interface for testing.
type mockProvider struct {
	verifyResult bool
}

func (m mockProvider) Verify(code string) bool {
	return m.verifyResult
}

func (m mockProvider) Generate(seed string) (int, error) {
	return 0, nil // Not used in this test
}

